        secretKey: awsSecretKey,
        region: 'us-east-1',
      );

      final fileBytes = await _selectedImage!.readAsBytes();
      final uploadResponse = await s3Client.putObject(
        bucket: 'hackathon-demo-bucket',
        key: 'images/${DateTime.now().millisecondsSinceEpoch}.jpg',
        body: fileBytes,
        contentType: 'image/jpeg',
      );

      final imageUrl = 'https://hackathon-demo-bucket.s3.amazonaws.com/${uploadResponse.key}';
      
      // Analyze with Google Cloud Vision
      final vision = Vision(imageUrl, googleApiKey);
